def conv(group):
    return {name: {"thr_mA": [p[0] for p in pts], "pct": [p[1] for p in pts]}
            for name, pts in group.items()}


def main():
    data = {
        "source": ("Bucksot et al. 2019 multi-fascicle recruitment, digitized by user "
                   "from the ASCENT figure, 2026-06-20"),
        "xlabel": "Activation threshold (mA)", "ylabel": "Fibers activated (%)",
        "fascicles": ["green", "red", "blue", "teal", "pink"],
        "circumferential": conv(CIRC),
        "inverted": conv(INV),
    }
    OUT.write_text(json.dumps(data, indent=2))
    nc = sum(len(v["thr_mA"]) for v in data["circumferential"].values())
    ni = sum(len(v["thr_mA"]) for v in data["inverted"].values())
    print(f"wrote {OUT.name}: circumferential {nc} pts, inverted {ni} pts (5 fascicles each)")


if __name__ == "__main__":
    main()
